// inside successful ajax
scrollFlag = false;

// bindings on table
$("#sortcontacts")
  .on("updateComplete", function() {
    // give layout time to redraw
    setTimeout(function() {
      scrollFlag = true;
    }, 500);
  })
  .on("sortEnd", function() {
    if (scrollflag) {
      $('html, body').animate({scrollTop: $(this).offset().top}, 1000);
    }
  });
```

