rs2_deproject_pixel_to_point(xyz, &depth_intrin, ij, depth.get_distance(ij[0], ij[1]));
rs2_transform_point_to_point(color_xyz, extrin, xyz);
rs2_project_point_to_pixel(color_ij, color_intrin, color_xyz);
```

